#include <iostream>
using namespace std;
int main()
{
    int a[1000]={0},n,i=1;
    cin>>n;
	a[0]=n;
    while(a[i-1]!=1)
    {
    	if(a[i-1]%2==1)
			a[i]=a[i-1]*3+1;
    	else
    		a[i]=a[i-1]/2;
    	i++;
    }
    for(int j=i-1;j>=0;j--)cout<<a[j]<<" ";
    return 0;
}
